mapper.update:
UPDATE film
judul = #{judul}, title_eng = #{titleEng}, tahun_rilis = #{tahunRilis}, jenis = #{jenis}, deskripsi = #{deskripsi}, catatan = #{catatan}, durasi = #{durasi}, negara_asal = #{negaraAsal}, original_language = #{originalLanguage}, color = #{color}, poster_url = #{posterUrl}, image_urls = #{imageUrls}, trailer_url = #{trailerUrl}, followed_by = #{followedBy}, part_of_series = #{partOfSeries},
WHERE id = #{id}

UPDATE person
photo_url = #{photoUrl}, description = #{description},
WHERE id = #{id}

mapper.select:
SELECT id, wikidata_qid, name, slug, description, photo_url
FROM person
WHERE slug = #{slug}

SELECT p.id, p.wikidata_qid, p.name, p.slug, p.description, p.photo_url
FROM person p
JOIN film_person fp ON fp.person_id = p.id
WHERE fp.film_id = #{filmId}
AND fp.role = #{role}
ORDER BY fp.id

mapper.update:
UPDATE company
logo_url = #{logoUrl}, description = #{description},
WHERE id = #{id}

mapper.select:
SELECT id, wikidata_qid, name, slug, description, logo_url
FROM company
WHERE slug = #{slug}

SELECT location
FROM film_location
WHERE film_id = #{filmId}
AND type = #{type}
ORDER BY id

SELECT alias FROM film_alias
WHERE film_id = #{filmId} AND language = #{language}
ORDER BY id
